mapper.insert:
MERGE INTO PUSH_SUBSCRIPTION t USING dual ON (t.ENDPOINT = #{endpoint})
WHEN MATCHED THEN UPDATE SET MEMBER_NO = #{memberNo}, P256DH = #{p256dh}, AUTH = #{auth}, USER_AGENT = #{userAgent}
WHEN NOT MATCHED THEN INSERT ( SUB_NO, MEMBER_NO, ENDPOINT, P256DH, AUTH, USER_AGENT ) VALUES ( SEQ_PUSH_SUB.NEXTVAL, #{memberNo}, #{endpoint}, #{p256dh}, #{auth}, #{userAgent} )
